// NetBox: Normalize & Filter
// Liest VMs + Devices aus vorherigen HTTP-Nodes (sequenziell, kein Fan-In-Problem).
const input      = $('📥 Input from Master').first().json;
const vmsData    = $('🔍 NetBox: Get VMs').first().json;
const devsData   = $('🔍 NetBox: Get Devices').first().json;

function extractIP(primaryIp) {
  if (!primaryIp || !primaryIp.address) return null;
  return primaryIp.address.split('/')[0];
}

function getOsFamily(platform) {
  if (!platform) return 'unknown';
  const s = ((platform.slug || platform.name || '')).toLowerCase();
  if (/debian|ubuntu|raspi|kali|mint|parrot|pop/.test(s))  return 'apt';
  if (/alpine/.test(s))                                     return 'apk';
  if (/arch|manjaro|endeavour/.test(s))                     return 'pacman';
  if (/fedora|rhel|centos|rocky|alma|oracle/.test(s))       return 'dnf';
  if (/suse|opensuse/.test(s))                              return 'zypper';
  if (/routeros|mikrotik/.test(s))                          return 'routeros';
  if (/openwrt/.test(s))                                    return 'opkg';
  if (/vyos/.test(s))                                       return 'vyos';
  if (/opnsense|pfsense/.test(s))                           return 'bsd';
  if (/windows/.test(s))                                    return 'windows';
  return 'unknown';
}

function normalizePlatform(raw) {
  if (!raw) return null;
  return { name: raw.name || '', slug: raw.slug || '' };
}

function normalizeVM(vm) {
  const cfVmType = vm.custom_fields && vm.custom_fields.vm_type;
  const type     = cfVmType === 'lxc' ? 'lxc' : 'vm';
  const platform = normalizePlatform(vm.platform);
  return {
    id: vm.id, name: vm.name,
    ip: extractIP(vm.primary_ip4 || vm.primary_ip),
    type, device_class: 'virtual', platform,
    os_family: getOsFamily(platform),
    ssh_user:     (vm.custom_fields && vm.custom_fields.ssh_user)     || 'root',
    ssh_password: (vm.custom_fields && vm.custom_fields.ssh_password) || '',
    cluster: vm.cluster ? vm.cluster.name : null,
    status:  vm.status  ? vm.status.value  : 'unknown'
  };
}

function normalizeDevice(dev) {
  const platform = normalizePlatform(dev.platform);
  const isVC = dev.virtual_chassis !== null && dev.virtual_chassis !== undefined;
  return {
    id: dev.id, name: dev.name,
    ip: extractIP(dev.primary_ip4 || dev.primary_ip),
    type: 'device',
    device_class: isVC ? 'virtual_device' : 'physical',
    platform, os_family: getOsFamily(platform),
    ssh_user:     (dev.custom_fields && dev.custom_fields.ssh_user)     || 'root',
    ssh_password: (dev.custom_fields && dev.custom_fields.ssh_password) || '',
    cluster: dev.site ? dev.site.name : null,
    status:  dev.status ? dev.status.value : 'unknown'
  };
}

const normalized = [];
for (const vm  of (vmsData.results  || [])) normalized.push(normalizeVM(vm));
for (const dev of (devsData.results || [])) normalized.push(normalizeDevice(dev));

const seen   = new Set();
const deduped = normalized.filter(item => {
  const key = item.type + '_' + item.id;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const byType = deduped.reduce((acc, s) => {
  acc[s.type] = (acc[s.type] || 0) + 1;
  return acc;
}, {});

const filter_by_type = input.filter_by_type || null;
const filter_by_ids  = input.filter_by_ids  ? JSON.parse(input.filter_by_ids) : null;
const hostname       = input.hostname       || null;

let filtered = [...deduped];

if (filter_by_type && filter_by_type !== '') {
  filtered = filtered.filter(s => s.type === filter_by_type);
}
if (filter_by_ids && Array.isArray(filter_by_ids) && filter_by_ids.length > 0) {
  const idSet = new Set(filter_by_ids.map(String));
  filtered = filtered.filter(s => idSet.has(String(s.id)));
}
if (hostname && hostname !== '') {
  const hn = hostname.toLowerCase();
  filtered = filtered.filter(s => s.name && s.name.toLowerCase().includes(hn));
}

const withIp = filtered.filter(s => s.ip);

if (withIp.length === 0) {
  return [{ json: {
    id: null, name: 'NO_SYSTEMS_FOUND', ip: null, type: null,
    device_class: null, platform: null, os_family: 'unknown',
    ssh_user: null, ssh_password: null, cluster: null, _empty: true,
    _debug: { filter_by_type, total_all: deduped.length, by_type: byType, filtered_count: filtered.length }
  } }];
}

return withIp.map(system => ({ json: system }));

